// Create an Animal class with:
// - a protected String field called "name"
// - a constructor that takes a String name
// - a speak() method that returns "..."

// Create a Dog class that extends Animal:
// - constructor that calls super(name)
// - override speak() to return "Woof! My name is " + name

// Create a Cat class that extends Animal:
// - constructor that calls super(name)
// - override speak() to return "Meow! My name is " + name

public class Main {
    public static void main(String[] args) {
        // Create a Dog named "Buddy" and a Cat named "Whiskers"
        // Print each animal's speak() result
    }
}

solution:
class Animal {
    protected String name;

    public Animal(String name) {
        this.name = name;
    }

    public String speak() {
        return "...";
    }
}

class Dog extends Animal {
    public Dog(String name) {
        super(name);
    }

    @Override
    public String speak() {
        return "Woof! My name is " + name;
    }
}

class Cat extends Animal {
    public Cat(String name) {
        super(name);
    }

    @Override
    public String speak() {
        return "Meow! My name is " + name;
    }
}

public class Main {
    public static void main(String[] args) {
        Dog buddy = new Dog("Buddy");
        Cat whiskers = new Cat("Whiskers");
        System.out.println(buddy.speak());
        System.out.println(whiskers.speak());
    }
}

