// Create a Shape class with:
// - an area() method that returns 0.0

// Create a Circle class that extends Shape:
// - a private double field "radius"
// - a constructor that takes the radius
// - override area() to return Math.PI * radius * radius

// Create a Rectangle class that extends Shape:
// - private double fields "width" and "height"
// - a constructor that takes width and height
// - override area() to return width * height

public class Main {
    public static void main(String[] args) {
        // Create a Circle with radius 5
        // Create a Rectangle with width 4, height 6
        // Print: "Circle area: " + the area
        // Print: "Rectangle area: " + the area
    }
}

solution:
class Shape {
    public double area() {
        return 0.0;
    }
}

class Circle extends Shape {
    private double radius;

    public Circle(double radius) {
        this.radius = radius;
    }

    @Override
    public double area() {
        return Math.PI * radius * radius;
    }
}

class Rectangle extends Shape {
    private double width;
    private double height;

    public Rectangle(double width, double height) {
        this.width = width;
        this.height = height;
    }

    @Override
    public double area() {
        return width * height;
    }
}

public class Main {
    public static void main(String[] args) {
        Circle c = new Circle(5);
        Rectangle r = new Rectangle(4, 6);
        System.out.println("Circle area: " + c.area());
        System.out.println("Rectangle area: " + r.area());
    }
}

