// Create Vehicle, Car, and Truck classes as described above
// Remember: Car and Truck constructors must call super(make, year) first!
// Remember: describe() in subclasses should call super.describe() to reuse parent logic

public class Main {
    public static void main(String[] args) {
        // Create a Car: "Toyota", 2023, 4 doors
        // Create a Truck: "Ford", 2022, 2.5 tons
        // Print: car.describe(), car.honk(), truck.describe(), truck.honk()
    }
}

solution:
class Vehicle {
    protected String make;
    protected int year;

    public Vehicle(String make, int year) {
        this.make = make;
        this.year = year;
    }

    public String describe() {
        return year + " " + make;
    }

    public String honk() {
        return "Beep!";
    }
}

class Car extends Vehicle {
    private int numDoors;

    public Car(String make, int year, int numDoors) {
        super(make, year);
        this.numDoors = numDoors;
    }

    @Override
    public String describe() {
        return super.describe() + " (" + numDoors + "-door car)";
    }

    @Override
    public String honk() {
        return "Honk honk!";
    }
}

class Truck extends Vehicle {
    private double payloadTons;

    public Truck(String make, int year, double payloadTons) {
        super(make, year);
        this.payloadTons = payloadTons;
    }

    @Override
    public String describe() {
        return super.describe() + " (truck, " + payloadTons + "T payload)";
    }

    @Override
    public String honk() {
        return "HOOOONK!";
    }
}

public class Main {
    public static void main(String[] args) {
        Car car = new Car("Toyota", 2023, 4);
        Truck truck = new Truck("Ford", 2022, 2.5);
        System.out.println(car.describe());
        System.out.println(car.honk());
        System.out.println(truck.describe());
        System.out.println(truck.honk());
    }
}

