// Create Employee class with name, salary, getTotalCompensation(), and toString()
// Create Manager class extending Employee with bonus field
// Manager overrides getTotalCompensation() to include bonus
// Manager overrides toString() to show bonus too

public class Main {
    public static void main(String[] args) {
        // Create an Employee[] array with 2 Employees and 2 Managers
        // Loop through and print: employee + " => Total: $" + getTotalCompensation()
    }
}

solution:
class Employee {
    protected String name;
    protected double salary;

    public Employee(String name, double salary) {
        this.name = name;
        this.salary = salary;
    }

    public double getTotalCompensation() {
        return salary;
    }

    @Override
    public String toString() {
        return name + " | Salary: $" + salary;
    }
}

class Manager extends Employee {
    private double bonus;

    public Manager(String name, double salary, double bonus) {
        super(name, salary);
        this.bonus = bonus;
    }

    @Override
    public double getTotalCompensation() {
        return salary + bonus;
    }

    @Override
    public String toString() {
        return name + " | Salary: $" + salary + " | Bonus: $" + bonus;
    }
}

public class Main {
    public static void main(String[] args) {
        Employee[] staff = {
            new Employee("Alice", 50000),
            new Manager("Bob", 70000, 15000),
            new Employee("Charlie", 45000),
            new Manager("Diana", 80000, 20000)
        };

        for (Employee e : staff) {
            System.out.println(e + " => Total: $" + e.getTotalCompensation());
        }
    }
}

