// Create the GameCharacter superclass
// Create Warrior, Mage, and Archer subclasses
// Each subclass needs: constructor with super() call, overridden attack(), overridden specialAbility()

public class Main {
    public static void main(String[] args) {
        // Create a GameCharacter[] array called party with:
        //   new Warrior("Thor", 120, 50)
        //   new Mage("Gandalf", 80, 100)
        //   new Archer("Legolas", 90, 30)

        // Print "=== Party Members ==="
        // Loop and print each character (uses toString())

        // Print a blank line, then "=== Attack Phase ==="
        // Loop and print each character's attack()

        // Print a blank line, then "=== Special Abilities ==="
        // Loop and print each character's specialAbility()
    }
}

solution:
class GameCharacter {
    protected String name;
    protected int health;

    public GameCharacter(String name, int health) {
        this.name = name;
        this.health = health;
    }

    public String attack() {
        return name + " does a basic attack!";
    }

    public String specialAbility() {
        return name + " has no special ability.";
    }

    @Override
    public String toString() {
        return name + " [HP: " + health + "]";
    }
}

class Warrior extends GameCharacter {
    private int armor;

    public Warrior(String name, int health, int armor) {
        super(name, health);
        this.armor = armor;
    }

    @Override
    public String attack() {
        return name + " swings a mighty sword! (Armor: " + armor + ")";
    }

    @Override
    public String specialAbility() {
        return name + " raises shield! Defense boosted!";
    }
}

class Mage extends GameCharacter {
    private int mana;

    public Mage(String name, int health, int mana) {
        super(name, health);
        this.mana = mana;
    }

    @Override
    public String attack() {
        return name + " casts a fireball! (Mana: " + mana + ")";
    }

    @Override
    public String specialAbility() {
        return name + " teleports away! Mana remaining: " + (mana - 20);
    }
}

class Archer extends GameCharacter {
    private int arrows;

    public Archer(String name, int health, int arrows) {
        super(name, health);
        this.arrows = arrows;
    }

    @Override
    public String attack() {
        return name + " shoots an arrow! (Arrows left: " + (arrows - 1) + ")";
    }

    @Override
    public String specialAbility() {
        return name + " fires a volley of 3 arrows! (Arrows left: " + (arrows - 3) + ")";
    }
}

public class Main {
    public static void main(String[] args) {
        GameCharacter[] party = {
            new Warrior("Thor", 120, 50),
            new Mage("Gandalf", 80, 100),
            new Archer("Legolas", 90, 30)
        };

        System.out.println("=== Party Members ===");
        for (GameCharacter c : party) {
            System.out.println(c);
        }

        System.out.println();
        System.out.println("=== Attack Phase ===");
        for (GameCharacter c : party) {
            System.out.println(c.attack());
        }

        System.out.println();
        System.out.println("=== Special Abilities ===");
        for (GameCharacter c : party) {
            System.out.println(c.specialAbility());
        }
    }
}
